CREATE OR REPLACE FUNCTION pass_contract_fts_match(search_vector tsvector, query text)
RETURNS boolean AS $$
    SELECT coalesce(search_vector @@ dcpass_fts_query(query), false);
$$ LANGUAGE sql IMMUTABLE;

